-- Build and show the history popup above the wibar (anchored top-right)
local function show_popup()
    close_popup()

    local rows = wibox.layout.fixed.vertical()

    -- Title row
    rows:add(wibox.widget {
        {
            {
                markup = string.format(
                    '<span font="Meslo LGS Regular 10" color="%s"><b> Notification history </b></span>',
                    fg_green
                ),
                widget = wibox.widget.textbox,
            },
            margins = 4,
            widget  = wibox.container.margin,
        },
        bg     = bg_popup,
        widget = wibox.container.background,
    })

    -- Separator
    rows:add(wibox.widget {
        color  = fg_grey,
        span_ratio = 1,
        widget = wibox.widget.separator,
    })

    -- Notification rows (newest first)
    for i = #history, 1, -1 do
        local n   = history[i]
        local msg = (n.title ~= "" and (n.title .. ": ") or "") .. n.message
        local row_bg = (i == #history) and bg_latest or bg_popup

        rows:add(wibox.widget {
            {
                {
                    markup = string.format(
                        '<span font="Meslo LGS Regular 9" color="%s">%s</span>'
                        .. '<span font="Meslo LGS Regular 9" color="%s">  %s</span>',
                        fg_grey,  gears.string.xml_escape(n.time),
                        fg_color, gears.string.xml_escape(msg)
                    ),
                    wrap   = "word_char",
                    widget = wibox.widget.textbox,
                },
                margins = { top = 3, bottom = 3, left = 6, right = 6 },
                widget  = wibox.container.margin,
            },
            bg     = row_bg,
            widget = wibox.container.background,
        })
    end

